// Project imports:
import 'package:baseball_detector_flutter/data/clients/static_file_client.dart';
import 'package:baseball_detector_flutter/data/models/failure/failure.dart';
import 'package:baseball_detector_flutter/data/models/maintenance_info.dart';
import 'package:baseball_detector_flutter/data/models/version_info.dart';
import 'package:baseball_detector_flutter/data/result.dart';

class FakeStaticFileClient extends StaticFileClient {
  VersionInfo? _versionInfo;
  MaintenanceInfo? _maintenanceInfo;
  Failure? _versionFailure;
  Failure? _maintenanceFailure;

  /// テスト用にバージョン情報を設定
  void setVersionInfo(VersionInfo versionInfo) {
    _versionInfo = versionInfo;
    _versionFailure = null;
  }

  /// テスト用にバージョン情報取得エラーを設定
  void setVersionFailure(Failure failure) {
    _versionFailure = failure;
    _versionInfo = null;
  }

  /// テスト用にメンテナンス情報を設定
  void setMaintenanceInfo(MaintenanceInfo maintenanceInfo) {
    _maintenanceInfo = maintenanceInfo;
    _maintenanceFailure = null;
  }

  /// テスト用にメンテナンス情報取得エラーを設定
  void setMaintenanceFailure(Failure failure) {
    _maintenanceFailure = failure;
    _maintenanceInfo = null;
  }

  @override
  Future<Result<Failure, VersionInfo>> fetchVersionInfo() async {
    if (_versionFailure != null) {
      return Left(_versionFailure!);
    }

    if (_versionInfo != null) {
      return Right(_versionInfo!);
    }

    // デフォルト値を返す
    return Right(VersionInfo(
      android: VersionInfoPlatform(
        required: '1.0.0+10',
        latest: '1.0.0+10',
      ),
      ios: VersionInfoPlatform(
        required: '1.0.0+10',
        latest: '1.0.0+10',
      ),
    ));
  }

  @override
  Future<Result<Failure, MaintenanceInfo>> fetchMaintenanceInfo() async {
    if (_maintenanceFailure != null) {
      return Left(_maintenanceFailure!);
    }

    if (_maintenanceInfo != null) {
      return Right(_maintenanceInfo!);
    }

    // デフォルト値を返す（メンテナンスなし）
    return Right(MaintenanceInfo(
      isInMaintenance: false,
      scheduledMaintenances: [
        ScheduledMaintenance(
          since: DateTime(2000, 1, 1),
          until: DateTime(2100, 1, 1),
        ),
      ],
    ));
  }

  /// テスト用にリセット
  void reset() {
    _versionInfo = null;
    _maintenanceInfo = null;
    _versionFailure = null;
    _maintenanceFailure = null;
  }
}

