      scheduledMaintenances: [
        // 過去のメンテナンス
        ScheduledMaintenance(
          since: now.subtract(const Duration(days: 1)),
          until: now.subtract(const Duration(hours: 22)),
          description: {
            'ja': '過去のメンテナンス',
            'en': 'Past maintenance',
