            'en': 'Scheduled future maintenance',
          },
        ),
      ],
    );
  }

  /// 時刻制限なしのメンテナンス（since が null）
  static MaintenanceInfo get noStartTimeLimit => MaintenanceInfo(
        isInMaintenance: true,
        scheduledMaintenances: [
          ScheduledMaintenance(
            since: null, // 開始時刻制限なし
            until: DateTime.now().add(const Duration(hours: 3)),
            description: {
              'ja': '臨時メンテナンス中',
              'en': 'Temporary maintenance in progress',
            },
          ),
        ],
      );

  /// 多言語メッセージのテストデータ
  static MaintenanceInfo get multiLanguageMessages => MaintenanceInfo(
        isInMaintenance: true,
        scheduledMaintenances: [
          ScheduledMaintenance(
            since: DateTime.now().subtract(const Duration(minutes: 10)),
            until: DateTime.now().add(const Duration(hours: 1)),
            description: {
              'ja': 'システムメンテナンス中です',
              'en': 'System maintenance in progress',
              'zh': '系统维护中',
              'ko': '시스템 점검 중',
              'fr': 'Maintenance du système en cours',
            },
          ),
        ],
      );

  /// 英語のみのメッセージ
  static MaintenanceInfo get englishOnlyMessage => MaintenanceInfo(
        isInMaintenance: true,
        scheduledMaintenances: [
          ScheduledMaintenance(
            since: DateTime.now().subtract(const Duration(minutes: 5)),
            until: DateTime.now().add(const Duration(hours: 2)),
            description: {
              'en': 'System maintenance - English only',
              'fr': 'Maintenance du système - français',
            },
          ),
        ],
      );

  /// 日本語も英語もないメッセージ
  static MaintenanceInfo get noJapaneseEnglishMessage => MaintenanceInfo(
        isInMaintenance: true,
        scheduledMaintenances: [
          ScheduledMaintenance(
            since: DateTime.now().subtract(const Duration(minutes: 5)),
            until: DateTime.now().add(const Duration(hours: 2)),
            description: {
              'fr': 'Maintenance en français',
              'de': 'Wartung auf Deutsch',
              'es': 'Mantenimiento en español',
            },
          ),
        ],
      );

  /// メッセージなしのメンテナンス
  static MaintenanceInfo get noDescription => MaintenanceInfo(
        isInMaintenance: true,
        scheduledMaintenances: [
          ScheduledMaintenance(
            since: DateTime.now().subtract(const Duration(minutes: 10)),
            until: DateTime.now().add(const Duration(hours: 1)),
            description: null,
          ),
        ],
      );

  /// 空のメッセージマップ
  static MaintenanceInfo get emptyDescription => MaintenanceInfo(
        isInMaintenance: true,
        scheduledMaintenances: [
          ScheduledMaintenance(
            since: DateTime.now().subtract(const Duration(minutes: 10)),
            until: DateTime.now().add(const Duration(hours: 1)),
            description: {},
          ),
        ],
      );

  /// メンテナンス中だがスケジュール情報なし
  static MaintenanceInfo get maintenanceWithoutSchedule => MaintenanceInfo(
        isInMaintenance: true,
        scheduledMaintenances: [],
      );

  /// リアルなシナリオ：週次メンテナンス
  static MaintenanceInfo get weeklyMaintenance {
    final now = DateTime.now();
    // 毎週日曜日の深夜2-4時のメンテナンス想定
    final lastSunday = now.subtract(Duration(days: now.weekday % 7));
    final maintenanceStart = DateTime(
      lastSunday.year,
      lastSunday.month,
      lastSunday.day,
      2, // 深夜2時
    );

    return MaintenanceInfo(
      isInMaintenance: false, // 通常は運用中
      scheduledMaintenances: [
        ScheduledMaintenance(
          since: maintenanceStart,
          until: maintenanceStart.add(const Duration(hours: 2)),
          description: {
            'ja': '定期メンテナンス（毎週日曜日 2:00-4:00）',
            'en': 'Weekly maintenance (Sundays 2:00-4:00 JST)',
          },
        ),
      ],
    );
  }

  /// リアルなシナリオ：緊急メンテナンス
  static MaintenanceInfo get emergencyMaintenance => MaintenanceInfo(
        isInMaintenance: true,
        scheduledMaintenances: [
          ScheduledMaintenance(
            since: DateTime.now().subtract(const Duration(minutes: 15)),
            until: null, // 復旧時間未定
            description: {
              'ja': '【緊急】システム障害のため緊急メンテナンス中です。復旧次第お知らせいたします。詳細はサポートページをご確認ください。',
              'en': '[EMERGENCY] Emergency maintenance due to system failure. We will notify you once service is restored. Please check our support page for details.',
            },
          ),
        ],
      );

  /// リアルなシナリオ：アップデートメンテナンス
  static MaintenanceInfo get updateMaintenance {
    final now = DateTime.now();
    return MaintenanceInfo(
      isInMaintenance: true,
      scheduledMaintenances: [
        ScheduledMaintenance(
          since: now.subtract(const Duration(minutes: 45)),
          until: now.add(const Duration(minutes: 15)), // あと15分で終了予定
          description: {
            'ja': 'v2.1.0アップデートのためメンテナンス中です。新機能：球種分析の精度向上、投球フォーム解析機能追加。',
            'en': 'Maintenance for v2.1.0 update. New features: Enhanced pitch type analysis, added pitching form analysis.',
          },
        ),
      ],
    );
  }
}

